args.sparql:
SELECT ?districtLabel WHERE {
  wd:Q327172 wdt:P131 ?district .  # Club Atlético Huracán located in ?district
  ?district rdfs:label ?districtLabel .
  FILTER (lang(?districtLabel) = "en")
}
LIMIT 10

SELECT ?districtLabel WHERE {
  wd:Q327172 wdt:P115 ?stadium .  # Club Atlético Huracán's home venue
  ?stadium wdt:P131 ?district .  # Stadium located in district
  ?district rdfs:label ?districtLabel .
  FILTER (lang(?districtLabel) = "en")
}

SELECT ?districtLabel WHERE {
  wd:Q327172 wdt:P115 ?stadium .
  ?stadium wdt:P131 ?district .
  ?district rdfs:label ?districtLabel .
  FILTER (lang(?districtLabel) = "en")
}
